#!/usr/bin/env bash
# backfill-5b-from-logs.sh — for builds that ran paris-residual-diff BEFORE
# the JSON-artifact step landed, parse the printed cosine table out of
# Cloud Build logs and synthesize the same v1 JSON, then upload to
# gs://${PROJECT}_paris5b/<build-id>-<model>-<slug>.json.
#
# Usage:
#   ./backfill-5b-from-logs.sh <BUILD_ID> [<BUILD_ID> ...]
#
# Best-effort: profile slug derived from `_RKNOT_R2_KEY` substitution.
set -euo pipefail

PROJECT="${PROJECT_ID:-neutral-418500}"
BUCKET="gs://${PROJECT}_paris5b"
MODEL="${MODEL_NAME:-llama-70b}"
TMP="$(mktemp -d)"
trap 'rm -rf "${TMP}"' EXIT

if [[ $# -eq 0 ]]; then
  echo "usage: $0 BUILD_ID [BUILD_ID ...]" >&2
  exit 1
fi

for BID in "$@"; do
  echo "── ${BID} ──"
  PROFILE=$(gcloud builds describe "${BID}" --format="value(substitutions._RKNOT_R2_KEY)" 2>/dev/null \
    || true)
  if [[ -z "${PROFILE}" ]]; then
    echo "  skip: no _RKNOT_R2_KEY substitution found" >&2
    continue
  fi
  SLUG="$(echo "${PROFILE}" | sed -E "s|.*/${MODEL}-?||; s|\.rknot$||")"
  [[ -z "${SLUG}" ]] && SLUG="canonical"
  echo "  profile=${PROFILE} slug=${SLUG}"

  LOG="${TMP}/${BID}.log"
  gcloud builds log "${BID}" > "${LOG}" 2>/dev/null || {
    echo "  skip: log fetch failed" >&2
    continue
  }

  ART="${TMP}/${BID}-${MODEL}-${SLUG}.json"
  python3 - "${LOG}" "${ART}" "${BID}" "${MODEL}" "${PROFILE}" <<'PYEOF'
import json, re, sys

log_path, out_path, build_id, model, profile = sys.argv[1:6]
rows = []
hidden_dim = None
with open(log_path) as f:
    for line in f:
        # The python step lines look like:
        #   Step #7 - "paris-residual-diff":   0    0.675929      4.7808e-01      ...
        m = re.search(
            r'paris-residual-diff":\s+'
            r'(\d+)\s+'
            r'(-?\d+\.\d+(?:[eE][-+]?\d+)?)\s+'
            r'(\d+\.\d+e[-+]\d+)\s+'
            r'(\d+\.\d+e[-+]\d+)\s+'
            r'(\d+\.\d+e[-+]\d+)\s+'
            r'(\d+\.\d+e[-+]\d+)\s*$',
            line.rstrip(),
        )
        if m:
            rows.append({
                'layer': int(m.group(1)),
                'cos': float(m.group(2)),
                'l2': float(m.group(3)),
                'linf': float(m.group(4)),
                'd_inf': float(m.group(5)),
                'r_inf': float(m.group(6)),
            })
            continue
        m = re.search(r'(\d+) layers x (\d+) dims', line)
        if m:
            hidden_dim = int(m.group(2))

if not rows:
    print(f"  no rows parsed from log; aborting", file=sys.stderr)
    sys.exit(2)

# Recompute cliffs/first-cos thresholds from parsed rows.
first99 = next((r['layer'] for r in rows if r['cos'] < 0.99), None)
first95 = next((r['layer'] for r in rows if r['cos'] < 0.95), None)
first90 = next((r['layer'] for r in rows if r['cos'] < 0.90), None)
cliffs = []
for i in range(1, len(rows)):
    jump = rows[i]['linf'] - rows[i-1]['linf']
    if jump > 5.0 and rows[i-1]['linf'] < 5.0:
        cliffs.append({'layer': rows[i]['layer'], 'from': rows[i-1]['linf'],
                       'to': rows[i]['linf'], 'jump': jump})

artifact = {
    'schema': 'paris-residual-diff/v1',
    'build_id': build_id,
    'model': model,
    'profile': profile,
    'prompt_tokens': '128000,791,6864,315,9822,374',  # canonical Paris prompt
    'num_layers': len(rows),
    'hidden_dim': hidden_dim,
    'first_cos_below': {'0.99': first99, '0.95': first95, '0.90': first90},
    'cliffs': cliffs,
    'l0': rows[0],
    'end': rows[-1],
    'rows': rows,
    'backfilled_from_logs': True,
}
with open(out_path, 'w') as f:
    json.dump(artifact, f, indent=2)
print(f"  parsed {len(rows)} rows, cliffs={[c['layer'] for c in cliffs]}, "
      f"L0 cos={rows[0]['cos']:.4f}, end ‖d-r‖∞={rows[-1]['linf']:.4e}")
PYEOF

  if [[ ! -f "${ART}" ]]; then
    echo "  skip: no artifact produced"
    continue
  fi

  DEST="${BUCKET}/${BID}-${MODEL}-${SLUG}.json"
  LATEST="${BUCKET}/latest-${MODEL}-${SLUG}.json"
  echo "  uploading -> ${DEST}"
  gsutil -q cp "${ART}" "${DEST}"
  echo "  uploading -> ${LATEST}"
  gsutil -q cp "${ART}" "${LATEST}"
done

echo
echo "Done. List:"
gsutil ls "${BUCKET}/" 2>/dev/null
